body:
If a `BindOp` needs to be hooked up to a temporary, the name generation logic is going to generate something that doesn't exist in the circuit. The problematic area is in this logic: https://github.com/llvm/circt/blob/main/lib/Translation/ExportVerilog/ExportVerilog.cpp#L2802

E.g, consider the following:

```mlir
module attributes {firrtl.mainModule = "Foo"}  {
  hw.module @Bar(%a: i1) {
    hw.output
  }
  sv.bind @__Bar__ {output_file = {directory = "", exclude_from_filelist = true, exclude_replicated_ops = true, name = "bindings.sv"}}
  hw.module @Foo(%a: i1) -> (%b: i1) {
    hw.instance "Bar" sym @__Bar__ @Bar(%0) {doNotPrint} : (i1) -> ()
    %x = sv.wire  : !hw.inout<i1>
    sv.connect %x, %a : i1
    %0 = sv.read_inout %x : !hw.inout<i1>
    %1 = sv.read_inout %x : !hw.inout<i1>
    hw.output %1 : i1
  }
}

```

This will produce Verilog that tries to bind to `Bar_Bar_a`.  I would expect to see the bind to `_T` or `x`:

```verilog
module Bar(
  input a);

endmodule

module Foo(
  input  a,
  output b);

  wire _T;      // Foo.mlir:10:10
  wire x;       // Foo.mlir:8:10

  // This instance is elsewhere emitted as a bind statement.
  // Bar Bar (  // Foo.mlir:7:5
  //   .a (_T)  // Foo.mlir:10:10
  // );
  assign x = a; // Foo.mlir:9:5
  assign _T = x;        // Foo.mlir:10:10
  assign b = x; // Foo.mlir:11:10, :12:5
endmodule


// ----- 8< ----- FILE "bindings.sv" ----- 8< -----

bind Foo Bar Bar (
  .a (Bar_Bar_a)
);
```
